import{_ as o,o as t,c as i,ag as a}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"Integrate NotebookLM with Gemini CLI, Google Antigravity or Other Agents with MCP","description":"","frontmatter":{"title":"Integrate NotebookLM with Gemini CLI, Google Antigravity or Other Agents with MCP","source":"https://medium.com/google-cloud/integrate-notebooklm-with-gemini-cli-google-antigravity-or-other-agents-with-mcp-cd83b575dc39","category":"[NotebookLM_Workflows]","clipped_at":"2026-04-04","tags":["notebooklm-workflows"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/NotebookLM_Workflows/NotebookLM_Workflows - Integrate-NotebookLM-with-Gemini-CLI,-Google-Antigravity-or-Other-Agents-with-MCP.md","filePath":"library/NotebookLM_Workflows/NotebookLM_Workflows - Integrate-NotebookLM-with-Gemini-CLI,-Google-Antigravity-or-Other-Agents-with-MCP.md","lastUpdated":null}'),s={name:"library/NotebookLM_Workflows/NotebookLM_Workflows - Integrate-NotebookLM-with-Gemini-CLI,-Google-Antigravity-or-Other-Agents-with-MCP.md"};function n(r,e,l,h,p,c){return t(),i("div",null,[...e[0]||(e[0]=[a(`<p><a href="https://notebooklm.google.com/" target="_blank" rel="noreferrer">NotebookLM</a> is awesome. Before we jump into the integration, I’m going to give you a quick overview of NotebookLM, in case you’re not familiar with it. But before I drop this overview, here’s an important thing to know:</p><p><strong>The following summary was created entirely with Gemini inside Antigravity, which is querying my existing NotebookLM notebook via the NotebookLM MCP server!</strong></p><p>If you have no idea what I’m talking about, then don’t worry. It will all become clear very soon.</p><p>Here’s the prompt I’ve used to create the summary below:</p><blockquote><p>Based on what you know from my notebook “The Power of NotebookLM”, provide a short summary of what NotebookLM is, its USPs, and some of its killer features, in Dazbo style.</p></blockquote><h2 id="overview-created-by-gemini-mcp-notebook" tabindex="-1">Overview Created by Gemini/MCP/Notebook <a class="header-anchor" href="#overview-created-by-gemini-mcp-notebook" aria-label="Permalink to &quot;Overview Created by Gemini/MCP/Notebook&quot;">​</a></h2><p>And here’s what Gemini responded with:</p><h3 id="what-is-notebooklm" tabindex="-1">What is NotebookLM? <a class="header-anchor" href="#what-is-notebooklm" aria-label="Permalink to &quot;What is NotebookLM?&quot;">​</a></h3><p>NotebookLM is a personalized AI research assistant built on top of Google’s multimodal Gemini models. It’s designed to help you understand, synthesize, and present complex information that’s scattered across all sorts of different formats.</p><h3 id="why-is-it-so-special-the-usps" tabindex="-1">Why is it so special? (The USPs) <a class="header-anchor" href="#why-is-it-so-special-the-usps" aria-label="Permalink to &quot;Why is it so special? (The USPs)&quot;">​</a></h3><ul><li><strong>Strict Source Grounding:</strong> This is the big one. General-purpose models can hallucinate — and often do when handling niche topics. But NotebookLM’s answers are grounded <em>only</em> in the documents you provide. Every claim it makes includes an inline citation linking directly back to the original passage in your sources. It’s exactly what you need when you have a low tolerance for AI hallucinations.</li><li><strong>A Massive 1 Million Token Context Window:</strong> It can analyze roughly 700,000 words at a single time. And the best part? This full 1-million token context window is available to everyone, even on the highly generous free tier.</li><li><strong>Extensive Multimodal Support:</strong> It handles an array of inputs. PDFs, Google Docs, Sheets, Word documents, images, web URLs, and even YouTube videos are all supported out of the box.</li></ul><h3 id="the-killer-features-where-it-really-shines" tabindex="-1">The Killer Features (Where it really shines) <a class="header-anchor" href="#the-killer-features-where-it-really-shines" aria-label="Permalink to &quot;The Killer Features (Where it really shines)&quot;">​</a></h3><ul><li><strong>Deep Research Agents:</strong> NotebookLM can actively search the web to find new sources for you. It builds a research plan, scans hundreds of sites, and generates a comprehensive, heavily cited 5-page report in minutes — effectively eliminating the manual grunt work of initial literature reviews.</li><li><strong>Audio and Video Overviews:</strong> You can instantly turn dense, boring source materials into an engaging, two-person podcast-style conversation! You can customize these Audio Overviews to focus on specific topics or even debate your work. Plus, it offers Video Overviews — narrated slides where the AI generates visuals and pulls diagrams and quotes from your documents to explain complex concepts visually.</li><li><strong>AI Slide Decks and Infographics:</strong> Powered by Nano Banana, NotebookLM can automatically transform your research into professional, presentation-ready slide decks and infographics. It essentially turns the platform into a complete “research-to-presentation” pipeline.</li><li><strong>Upgraded Studio Output:</strong> NotebookLM doesn’t just answer questions; it actively organizes your content into actionable formats — like Briefing Documents, Study Guides, FAQs, and Mind Maps. Through the Studio panel, you can generate multiple formats.</li></ul><p><img src="https://miro.medium.com/v2/resize:fit:2000/format:webp/1*vXLnqIDiH7XddDK5btQeEQ.png" alt=""></p><p>Generated by NotebookLM from my notebook: “The Power of NotebookLM”</p><h2 id="speaking-to-your-notebooks-from-your-ai-tools" tabindex="-1">Speaking to Your Notebooks from Your AI Tools <a class="header-anchor" href="#speaking-to-your-notebooks-from-your-ai-tools" aria-label="Permalink to &quot;Speaking to Your Notebooks from Your AI Tools&quot;">​</a></h2><p>I live in tools like Google Antigravity and Gemini CLI. Wouldn’t it be great if, from these tools, I could:</p><ul><li>Query my existing NotebookLM notebooks</li><li>Create new notebooks, e.g. based on research I’m doing in Gemini CLI</li><li>Perform research by <em>combining</em> my notebooks</li></ul><p>Well, you can. And in a minute, I’ll show you how.</p><h3 id="recap-mcp" tabindex="-1">Recap: MCP <a class="header-anchor" href="#recap-mcp" aria-label="Permalink to &quot;Recap: MCP&quot;">​</a></h3><p>The <strong>Model Context Protocol (MCP)</strong> is an open standard that allows AI models and agents to safely and easily interact with external tools, APIs, and data. Think of it as the universal adapter that allows models and agents to find and execute the tools it has access to.</p><p>TL;DR:</p><p>Integrating LLMs used to mean writing custom, brittle API connections for every single data source — a classic <code>M*N</code> maintenance nightmare. MCP solves this. Instead of hard-coding the plumbing, the LLM just interprets your <strong>natural language</strong> requests and figures out which tools to use on the fly. You ask it to do something, the LLM tells the MCP client what tool it needs, and the client routes it to the right server to grab the data or run the action.</p><p><img src="https://miro.medium.com/v2/resize:fit:2000/format:webp/1*9WNJecPncDjGwEOQicOiVg.png" alt=""></p><p>Generated by NotebookLM from my Notebook: Integrating Agents Using MCP</p><p>Because MCP creates a universal standard — often described as the <em>”USB-C for AI applications”</em> — it unlocks massive <strong>off-the-shelf reusability</strong>. Developers can build an MCP server once, and any MCP-compatible AI client (like Gemini CLI, Antigravity, or your own agents) can instantly connect to it.</p><h3 id="notebooklm-mcp-server" tabindex="-1">NotebookLM MCP Server <a class="header-anchor" href="#notebooklm-mcp-server" aria-label="Permalink to &quot;NotebookLM MCP Server&quot;">​</a></h3><p>I wondered: <em>“Is there an existing NotebookLM MCP server I can use?”</em></p><p>Of course there is! A very brief search led me to <a href="https://github.com/jacob-bd/notebooklm-mcp-cli" target="_blank" rel="noreferrer">https://github.com/jacob-bd/notebooklm-mcp-cli</a>. And it’s clearly very popular.</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*cCNQIl10FQgxn4w161-zSw.jpeg" alt=""></p><p>NotebookLM CLI MCP</p><h3 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h3><p>I’ll show you how I got it working. It only took a couple of minutes. Note that I’m using WSL Ubuntu, which creates the need for an extra step.</p><p>From your terminal:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># If you</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;re running in Linux or WSL, make sure you can launch Chrome or Chromium, e.g.</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sudo apt install chromium-browser</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"># Now install NotebookLM MCP CLI</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">uv tool install notebooklm-mcp-cli</span></span></code></pre></div><p>Let’s check the <strong>NotebookLM CLI</strong> is working by running the <code>nlm</code> command:</p><p><img src="https://miro.medium.com/v2/resize:fit:2000/format:webp/1*BIKl3FaC-MIqt4rrQ2XOeQ.png" alt=""></p><p>nlm command</p><p>So far, so good!</p><p>Next, I’ll authenticate with <code>nlm</code> so that the CLI/MCP is able to access my own notebooks:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nlm login</span></span></code></pre></div><p>Great, we’re authenticated.</p><p>Finally, let’s add the <strong>MCP configuration</strong> to our tool of choice by updating our MCP configuration. E.g.</p><ul><li>In Antigravity, you’ll add this to <code>.gemini/antigravity/mcp_config.json</code></li><li>In Gemini CLI, add it to <code>.gemini/settings.json</code></li></ul><p>This is the configuration we need to add:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // other MCP servers  </span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;notebooklm-mcp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;uvx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;--from&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;notebooklm-mcp-cli&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;notebooklm-mcp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span></code></pre></div><h3 id="try-it-out" tabindex="-1">Try It Out <a class="header-anchor" href="#try-it-out" aria-label="Permalink to &quot;Try It Out&quot;">​</a></h3><p>If I now run <code>/mcp</code> from Gemini CLI, I can see it contains this in the output:</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*ETTtcolBCnRb1ho1PyU3Jg.png" alt=""></p><p>NotebookLM MCP tools in Gemini CLI</p><p>So now, using natural language commands, we can do things like:</p><ul><li>List notebooks.</li><li>Create and delete notebooks.</li><li>Query notebooks.</li><li>Invite collaborators by email.</li><li>Add sources.</li><li>Perform deep research on a topic.</li><li>Create studio artifacts, such as podcasts, videos, slide decks, infographics, mindmaps, and more.</li><li>Download NotebookLM artifacts, e.g. audio podcasts as MP3, videos as MP4, reports as markdown, slide decks as PDF or PPTX, infographics as PNG, and so on.</li></ul><p>Let’s try some natural language queries in Google Antigravity.</p><blockquote><p>What notebooklm notebooks do I have?</p></blockquote><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*VFF9e4A3i9JNuJnn9JP6nA.png" alt=""></p><p>NotebookLM MCP listing my notebooks</p><blockquote><p>What tools do you have for working with notebookLM?</p></blockquote><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*VI5KHEj5PcO-7-pzdD5BWw.png" alt=""></p><p>NotebookLM MCP telling me about its tools</p><h3 id="working-with-my-power-of-notebooklm-notebook" tabindex="-1">Working with my “Power of NotebookLM Notebook” <a class="header-anchor" href="#working-with-my-power-of-notebooklm-notebook" aria-label="Permalink to &quot;Working with my “Power of NotebookLM Notebook”&quot;">​</a></h3><p>I wanted to take <em>this blog</em> and add it to my existing notebook about NotebookLM. Yeah, I know it’s a bit <em>meta</em>.</p><p>First, let’s look at the sources that make up this notebook:</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*KNeBc-hj4RPjK7iDUXT5BA.png" alt=""></p><p>Sources in my notebook</p><p>So I created a PDF of this blog (whilst I’m still writing it), added to to the root of my Antigravity workspace, and then gave this prompt to the Gemini agent:</p><blockquote><p>Please add my “Integrate NotebookLM” PDF to my “Power of NotebookLM” notebook.</p></blockquote><p>The actual PDF was called “Integrate NotebookLM with Gemini CLI, Google Antigravity or Other Agents with MCP.pdf”, but of course, Gemini is easily able to work out which file I’m talking about.</p><p><img src="https://miro.medium.com/v2/resize:fit:1382/format:webp/1*6ef8_qk29pB6VqzUKd47kA.png" alt=""></p><p>Adding to my notebook inside Antigravity</p><p>That was fast! Let’s see if it worked…</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*cfJOfZjYSSypIJOpCPe30Q.png" alt=""></p><p>Sources in my notebook — with one more!</p><p><em>Et voilà!</em> The new source has been added. That was easy.</p><p>Now, still in Antigravity, let’s create an infographic on this topic. Here’s my prompt:</p><blockquote><p>Create an infographic in that notebook, showing how we can use NotebookLM MCP to integrate agentic clients (including Gemini CLI, Antigravity, or other agents) to your NotebookLM notebooks. It should have a modern look-and-feel with white background.</p></blockquote><p>The Antigravity Gemini agent immediately determines that the <code>studio_create</code> tool needs to be used. Here’s the output in Antigravity:</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*v8eMNADX_yHkIx9ZcVideQ.png" alt=""></p><p>Antigravity response to “create an infographic…”</p><p>Of course, the infographic generation takes a while and is generated by NotebookLM asynchronously. After a couple of minutes, the infographic has been created, and is also saved directly to my Antigravity workspace!</p><p><img src="https://miro.medium.com/v2/resize:fit:1400/format:webp/1*7hTlHjy3MYmQQECM-l9hvw.png" alt=""></p><p>Infographic has been created</p><p>And here’s the infographic:</p><p><img src="https://miro.medium.com/v2/resize:fit:2000/format:webp/1*TeYHQq2JoxLcOzQWwBXNSA.png" alt=""></p><p>Infographic about integrating NotebookLM with MCP</p><p>I like it. I’ll use it as the header image for this blog.</p><h2 id="wrap-up" tabindex="-1">Wrap-Up <a class="header-anchor" href="#wrap-up" aria-label="Permalink to &quot;Wrap-Up&quot;">​</a></h2><p>Let’s wrap up this blog by getting NotebookLM to do it, once again from the agent inside Antigravity. Here’s my prompt:</p><blockquote><p>Based on the “Integrate NotebookLM” source in my notebook, create a wrap-up in Dazbo style.</p></blockquote><p>The response was pretty good. And here it is, only slightly tweaked and shortened by me:</p><p>Here’s the bottom line. Historically, integrating an incredibly powerful research engine like NotebookLM into your own custom AI agents required a lot of work.</p><p>But with the Model Context Protocol (MCP) — which is essentially the ultimate “USB-C for AI applications” — all of that pain just vanishes. By dropping the NotebookLM MCP server into your favourite AI environment (whether that’s Gemini CLI, Google Antigravity, or your own custom agent), you instantly unlock the ability to control NotebookLM using nothing but natural language.</p><p>Think about it. You can ask your agent to spin up a new notebook, cross-reference data across hundreds of sources, dynamically search the web for new references, or even kick off the generation of a podcast or a slide deck — all without ever leaving your command line or your IDE.</p><p>It completely transforms NotebookLM from a brilliant standalone web app into a robust, heavily cited backend research service that powers your autonomous agents.</p><h2 id="before-you-go" tabindex="-1">Before You Go <a class="header-anchor" href="#before-you-go" aria-label="Permalink to &quot;Before You Go&quot;">​</a></h2><ul><li><strong>Please share</strong> this with anyone that you think will be interested. It might help them, and it really helps me!</li><li>Please <strong>give me 50 claps</strong>! (Just hold down the clap button.)</li><li>Feel free to <strong>leave a comment</strong> 💬.</li><li><strong>Follow</strong> and <strong>subscribe,</strong> so you don’t miss my content.</li></ul><h2 id="useful-links-and-references" tabindex="-1">Useful Links and References <a class="header-anchor" href="#useful-links-and-references" aria-label="Permalink to &quot;Useful Links and References&quot;">​</a></h2><ul><li><a href="https://notebooklm.google.com/" target="_blank" rel="noreferrer">NotebookLM</a></li><li><a href="https://medium.com/google-cloud/notebooklm-is-googles-insanely-cool-personal-ai-research-assistant-a2a36186f683" target="_blank" rel="noreferrer">NotebookLM is Google’s INSANELY COOL Personal AI Research Assistant</a></li><li><a href="https://antigravity.google/" target="_blank" rel="noreferrer">Google Antigravity</a></li><li><a href="https://geminicli.com/" target="_blank" rel="noreferrer">Gemini CLI</a></li><li><a href="https://github.com/jacob-bd/notebooklm-mcp-cli" target="_blank" rel="noreferrer">NotebookLM MCP CLI</a></li><li><a href="http://darrenlester.net/" target="_blank" rel="noreferrer">My Portfolio / Blogs / Applications</a></li></ul>`,97)])])}const m=o(s,[["render",n]]);export{u as __pageData,m as default};
